import React from 'react';

function Achievements({ data }) {
  if (!data) return null;

  return (
    <section id="achievements" className="py-16 md:py-24 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-12">
          Achievements
        </p>

        <div className="space-y-8">
          {data.map((achievement) => (
            <div key={achievement.id} className="border-b border-gray-200 pb-8 last:border-0">
              <h3 className="text-2xl font-black text-gray-900 mb-2">
                {achievement.title}
              </h3>
              <p className="text-sm text-gray-500 uppercase tracking-wider">
                {achievement.year}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Achievements;
